export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  if (liveCells.length === 0) {
    return [];
  }

  // Count neighbors for a specific cell
  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
          count++;
        }
      }
    }
    return count;
  };

  // Check if [1, 1] exists in the current generation
  const hasCell11 = liveCells.some(([x, y]) => x === 1 && y === 1);
  const neighbors11 = countNeighbors(1, 1);

  // Apply rules for cell [1, 1]
  if (!hasCell11 && neighbors11 === 3) {
    // Reproduction: dead cell with exactly 3 neighbors is born
    return [[1, 1]];
  }

  if (hasCell11 && (neighbors11 === 2 || neighbors11 === 3)) {
    // Survival: live cell with 2 or 3 neighbors survives
    return [[1, 1]];
  }

  return [];
}

