export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  if (liveCells.length === 0) {
    return [];
  }

  // Count neighbors for a specific cell
  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
          count++;
        }
      }
    }
    return count;
  };

  // Check which cells survive or are born
  const survivingCells: Array<[number, number]> = [];

  // Check all live cells for survival
  for (const [x, y] of liveCells) {
    const neighborCount = countNeighbors(x, y);
    if (neighborCount === 2 || neighborCount === 3) {
      survivingCells.push([x, y]);
    }
  }

  // Check cells adjacent to live cells for reproduction
  const cellsToCheck = new Set<string>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        cellsToCheck.add(`${x + dx},${y + dy}`);
      }
    }
  }

  for (const cellKey of cellsToCheck) {
    const [x, y] = cellKey.split(',').map(Number) as [number, number];
    const isAlive = liveCells.some(([cx, cy]) => cx === x && cy === y);
    if (!isAlive) {
      const neighborCount = countNeighbors(x, y);
      if (neighborCount === 3) {
        survivingCells.push([x, y]);
      }
    }
  }

  return survivingCells.sort((a, b) => (a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]));
}

